package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Mock JsonElement input for constructor (can be null since we won't use it directly)
    reader = new JsonTreeReader(null);

    // Setup internal state for testing endArray
    // stackSize = 2 (to allow stack pops and pathIndices increment)
    setField(reader, "stackSize", 2);

    // Initialize stack with dummy objects (not null) to avoid NullPointerException on popStack
    Object[] stack = new Object[32];
    stack[0] = new Object();
    stack[1] = new Object();
    setField(reader, "stack", stack);

    // Initialize pathIndices with zeroes
    int[] pathIndices = new int[32];
    pathIndices[0] = 0;
    pathIndices[1] = 0;
    setField(reader, "pathIndices", pathIndices);
  }

  @Test
  public void testEndArray_normal() throws Exception {
    // Spy on reader to verify expect and popStack calls
    JsonTreeReader spyReader = spy(reader);

    // Mock expect(JsonToken.END_ARRAY) to do nothing (no exception)
    doNothing().when(spyReader).expect(JsonToken.END_ARRAY);

    // Mock popStack to return dummy objects (simulate stack pop)
    doReturn(new Object()).when(spyReader).popStack();

    // Call endArray
    spyReader.endArray();

    // Verify expect called once with END_ARRAY
    verify(spyReader, times(1)).expect(JsonToken.END_ARRAY);

    // Verify popStack called twice
    verify(spyReader, times(2)).popStack();

    // Verify pathIndices[stackSize - 1] incremented by 1
    int[] pathIndices = getField(spyReader, "pathIndices");
    int stackSize = getField(spyReader, "stackSize");
    assertEquals(1, pathIndices[stackSize - 1]);
  }

  @Test
  public void testEndArray_stackSizeZero_noIncrement() throws Exception {
    // Set stackSize to 0 to test no increment branch
    setField(reader, "stackSize", 0);

    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.END_ARRAY);
    doReturn(new Object()).when(spyReader).popStack();

    spyReader.endArray();

    verify(spyReader, times(1)).expect(JsonToken.END_ARRAY);
    verify(spyReader, times(2)).popStack();

    int[] pathIndices = getField(spyReader, "pathIndices");
    // Since stackSize is 0, no increment should occur, all zeros
    for (int i = 0; i < pathIndices.length; i++) {
      assertEquals(0, pathIndices[i]);
    }
  }

  @Test
  public void testEndArray_expectThrows() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doThrow(new IllegalStateException("Expected END_ARRAY")).when(spyReader).expect(JsonToken.END_ARRAY);

    IllegalStateException thrown = assertThrows(IllegalStateException.class, spyReader::endArray);
    assertEquals("Expected END_ARRAY", thrown.getMessage());

    // popStack should not be called if expect throws
    verify(spyReader, never()).popStack();
  }

  // Helper to set private fields via reflection
  @SuppressWarnings("unchecked")
  private <T> T getField(Object target, String name) throws Exception {
    Field field = JsonTreeReader.class.getDeclaredField(name);
    field.setAccessible(true);
    return (T) field.get(target);
  }

  private void setField(Object target, String name, Object value) throws Exception {
    Field field = JsonTreeReader.class.getDeclaredField(name);
    field.setAccessible(true);
    field.set(target, value);
  }
}
